import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import { formatBRL } from "@/lib/utils";
import type { Metadata } from "next";
import { EnterpriseCard, EnterpriseStat } from "@/components/ui/EnterpriseCard";

export const metadata: Metadata = { title: "Dashboard" };

async function getDashboardData(therapistId: string) {
  const supabase = await createClient();
  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
  const lastMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1).toISOString();
  const lastMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0).toISOString();

  const [patientsResult, sessionsThisMonth, sessionsLastMonth, paymentsThisMonth, paymentsLastMonth, upcomingToday] =
    await Promise.all([
      supabase.from("patients").select("id, status, mood_score").eq("therapist_id", therapistId).in("status", ["active", "new"]),
      supabase.from("sessions").select("id, nps_score").eq("therapist_id", therapistId).gte("created_at", startOfMonth),
      supabase.from("sessions").select("id, nps_score").eq("therapist_id", therapistId).gte("created_at", lastMonthStart).lte("created_at", lastMonthEnd),
      supabase.from("payments").select("amount").eq("therapist_id", therapistId).eq("status", "paid").gte("created_at", startOfMonth),
      supabase.from("payments").select("amount").eq("therapist_id", therapistId).eq("status", "paid").gte("created_at", lastMonthStart).lte("created_at", lastMonthEnd),
      supabase
        .from("appointments")
        .select(`
          id, scheduled_at, status, type,
          patient:patients(name, telegram_chat_id)
        `)
        .eq("therapist_id", therapistId)
        .gte("scheduled_at", new Date(now.setHours(0, 0, 0, 0)).toISOString())
        .lte("scheduled_at", new Date(now.setHours(23, 59, 59, 999)).toISOString())
        .order("scheduled_at"),
    ]);

  const activePatients = patientsResult.data?.length ?? 0;
  const sessionsCount = sessionsThisMonth.data?.length ?? 0;
  const sessionsCountLast = sessionsLastMonth.data?.length ?? 0;

  const mrr = paymentsThisMonth.data?.reduce((acc, p) => acc + Number(p.amount), 0) ?? 0;
  const mrrLast = paymentsLastMonth.data?.reduce((acc, p) => acc + Number(p.amount), 0) ?? 0;
  const mrrDelta = mrrLast > 0 ? ((mrr - mrrLast) / mrrLast) * 100 : 0;

  const npsScores = (sessionsThisMonth.data ?? []).filter((s) => s.nps_score !== null).map((s) => s.nps_score!);
  const npsAvg = npsScores.length > 0 ? npsScores.reduce((a, b) => a + b, 0) / npsScores.length : 0;

  return {
    mrr,
    mrrDelta,
    sessionsCount,
    sessionsDelta: sessionsCountLast > 0 ? sessionsCount - sessionsCountLast : 0,
    activePatients,
    npsAvg: Math.round(npsAvg * 20),
    todayAppointments: upcomingToday.data ?? [],
  };
}

export default async function DashboardPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) redirect("/auth/login");

  const { data: therapist } = await supabase
    .from("therapists")
    .select("id, name, onboarding_completed")
    .eq("user_id", user.id)
    .single();

  if (!therapist) redirect("/auth/login");
  if (!therapist.onboarding_completed) redirect("/dashboard/onboarding");

  const kpis = await getDashboardData(therapist.id);

  const hour = new Date().getHours();
  const greeting = hour < 12 ? "Bom dia" : hour < 18 ? "Boa tarde" : "Boa noite";
  const todayDateStr = new Date().toLocaleDateString("pt-BR", { weekday: "long", day: "numeric", month: "long" });

  return (
    <div className="w-full max-w-[1640px] mx-auto px-4 py-8 sm:px-8 lg:px-10 xl:px-12 space-y-10 animate-[fadeUp_.4s_ease-out_both]">
      {/* Header */}
      <div className="flex flex-col gap-2">
        <h1 className="text-[36px] sm:text-[44px] lg:text-[52px] font-light text-[var(--color-text-primary)] font-[family-name:var(--font-display)] tracking-tight leading-[1.04]">
          {greeting}, <em className="text-[var(--color-brand)] not-italic font-normal">{therapist.name.split(" ")[0]}</em>
        </h1>
        <p className="text-[15px] font-light text-[var(--color-text-secondary)] capitalize">{todayDateStr}</p>
      </div>

      {/* KPI Grid */}
      <div className="grid grid-cols-1 gap-5 md:grid-cols-2 xl:grid-cols-4">
        <EnterpriseStat delay={0.05} label="MRR (Receita)" value={formatBRL(kpis.mrr)} trend={kpis.mrrDelta} trendLabel="vs último mês" />
        <EnterpriseStat delay={0.1} label="Sessões no mês" value={String(kpis.sessionsCount)} trend={kpis.sessionsDelta} />
        <EnterpriseStat delay={0.15} label="Pacientes Ativos" value={String(kpis.activePatients)} />
        <EnterpriseStat delay={0.2} label="NPS Médio" value={`${kpis.npsAvg}/100`} />
      </div>

      {/* Today's agenda */}
      <EnterpriseCard delay={0.3} className="w-full p-8 lg:p-10">
        <h2 className="mb-6 text-[30px] font-light tracking-tight text-[var(--color-text-primary)] font-[family-name:var(--font-display)]">
          Agenda de Hoje
        </h2>
        
        {kpis.todayAppointments.length === 0 ? (
          <div className="flex min-h-[220px] flex-col items-center justify-center rounded-2xl border border-dashed border-[var(--color-border-strong)] bg-[var(--color-surface-hover)]/35 px-6 text-center text-[var(--color-text-muted)]">
            <span className="mb-3 text-3xl opacity-60">☕</span>
            <p className="text-[16px] font-light text-[var(--color-text-secondary)]">Nenhuma sessão agendada para hoje.</p>
          </div>
        ) : (
          <div className="flex flex-col gap-3">
            {kpis.todayAppointments.map((appt) => {
              const time = new Date(appt.scheduled_at).toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit" });
              const patient = appt.patient as unknown as { name: string } | null;
              
              const isConfirmed = appt.status === "confirmed";
              const isInProgress = appt.status === "in_progress";
              const statusColor = isConfirmed ? "text-[var(--color-brand)] ring-[var(--color-brand)]/20 bg-[var(--color-brand)]/10" 
                               : isInProgress ? "text-amber-400 ring-amber-400/20 bg-amber-400/10" 
                               : "text-[var(--color-text-muted)] ring-[var(--color-border-subtle)] bg-[var(--color-surface-hover)]";

              return (
                <div key={appt.id} className="group flex items-center justify-between gap-6 p-5 rounded-2xl bg-[var(--color-surface-hover)] border border-[var(--color-border-subtle)] transition duration-300 hover:border-[var(--color-border-strong)] hover:shadow-md cursor-pointer">
                  
                  <div className="flex items-center gap-5">
                    <div className="font-[family-name:var(--font-display)] text-[28px] text-[var(--color-text-secondary)] group-hover:text-[var(--color-text-primary)] transition-colors min-w-[70px] font-light">
                      {time}
                    </div>
                    <div className="flex flex-col">
                      <div className="text-[16px] tracking-wide font-light text-[var(--color-text-primary)] transition-colors">
                        {patient?.name ?? "Paciente Excluído"}
                      </div>
                      <div className="text-[13px] text-[var(--color-text-muted)] mt-1 font-light">
                        {appt.type === "online" ? "🎥 Telepsicologia" : "🏢 Consultório"}
                      </div>
                    </div>
                  </div>
                  
                  <div className={`px-4 py-1.5 text-[12px] font-medium rounded-full ring-1 ring-inset ${statusColor} shrink-0`}>
                    {isConfirmed ? "Confirmado" : isInProgress ? "Em Sala" : appt.status}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </EnterpriseCard>
    </div>
  );
}
